// Mark arc d-values (shared by every variant).
const ARC_OUTER = 'M76.86 23.96 A34 34 0 1 0 76.86 76.04';
const ARC_INNER = 'M64.65 38.51 A15 15 0 1 0 64.65 61.49';

/**
 * Shared horizontal lockup. `stroke` colours the mark, `fill` the wordmark.
 */
function HorizontalLogo({ stroke, fill, className, ...props }) {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 488 100"
            role="img"
            aria-label="Doccentia"
            className={className}
            {...props}
        >
            <g fill="none" stroke={stroke} strokeLinecap="round">
                <path d={ARC_OUTER} strokeWidth="13" />
                <path d={ARC_INNER} strokeWidth="12" />
            </g>
            <g transform="translate(98.23 78.83) scale(0.079)">
                <path d={WORDMARK} fill={fill} />
            </g>
        </svg>
    );
}

// Logo horizontal teal (uso principal — header claro)
export function LogoHorizontalTeal(props) {
    return <HorizontalLogo stroke="#0E6E5E" fill="#16201C" {...props} />;
}

// Logo horizontal blanco (uso en headers oscuros / sidebar dark)
export function LogoHorizontalWhite(props) {
    return <HorizontalLogo stroke="#FFFFFF" fill="#FFFFFF" {...props} />;
}

// Logo ámbar sobre crema
export function LogoAmber(props) {
    return <HorizontalLogo stroke="#A16F27" fill="#A16F27" {...props} />;
}

// Monocromo blanco (sobre slate/oscuro)
export function LogoMono(props) {
    return <HorizontalLogo stroke="#FFFFFF" fill="#FFFFFF" {...props} />;
}

// Logo vertical teal (sobre crema) — símbolo arriba, wordmark debajo.
export function LogoVertical({ className, ...props }) {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 390 235"
            role="img"
            aria-label="Doccentia"
            className={className}
            {...props}
        >
            <g fill="none" stroke="#0E6E5E" strokeLinecap="round" transform="translate(145 8)">
                <path d={ARC_OUTER} strokeWidth="13" />
                <path d={ARC_INNER} strokeWidth="12" />
            </g>
            <g transform="translate(3 215) scale(0.079)">
                <path d={WORDMARK} fill="#16201C" />
            </g>
        </svg>
    );
}

/**
 * Solo el símbolo (mark) — para favicon, app icon, sidebar colapsado.
 */
export function DoccentiaMark({ color = '#0E6E5E', size = 32, className, ...props }) {
    return (
        <svg
            width={size}
            height={size}
            viewBox="0 0 100 100"
            fill="none"
            role="img"
            aria-label="Doccentia"
            className={className}
            {...props}
        >
            <path d={ARC_OUTER} stroke={color} strokeWidth="13" strokeLinecap="round" />
            <path d={ARC_INNER} stroke={color} strokeWidth="12" strokeLinecap="round" />
        </svg>
    );
}

export default LogoHorizontalTeal;
